proof_block:
// `Array::new()` only ensures `ret.wf()`, which unfolds to
// `ret.seq@.len() == N`. Surface that fact for both candidate
// outputs so triggers line up. The struct `Array<A, N>` has fields
// `{ seq: Ghost<Seq<A>>, ar: [A; N] }`; structural equality
// `r1 == r2` requires both fields equal, and `wf` does not pin the
// element contents of either field.
if r1.wf() && r2.wf() {
    // Per-output length facts from `wf`.
    assert(r1.seq@.len() == N);
    assert(r2.seq@.len() == N);
    // Joint length agreement (helps any trigger looking at both seqs).
    assert(r1.seq@.len() == r2.seq@.len());
    // View is `#[verifier(inline)]` over `seq@`, so the same fact in
    // view form may unlock view-keyed triggers.
    assert(r1.view().len() == N);
    assert(r2.view().len() == N);
    assert(r1.view().len() == r2.view().len());
}
// Unguarded (implication) versions, so a trigger that fires only on
// the bare `wf()` term in the postcondition also sees the length fact.
assert(r1.wf() ==> r1.seq@.len() == N);
assert(r2.wf() ==> r2.seq@.len() == N);
assert(r1.wf() && r2.wf() ==> r1.seq@.len() == r2.seq@.len());
